USE RideOn;
GO

/* =========================================================
   InsertData_01_Persons.sql
   כולל:
   - Person
   - FederationMember
   - SystemUser
   ========================================================= */

CREATE TABLE #FilteredFederationMembers
(
    NationalId VARCHAR(9) NULL,
    FirstName NVARCHAR(50) NOT NULL,
    LastName NVARCHAR(50) NOT NULL,
    Gender NVARCHAR(10) NOT NULL,
    DateOfBirth DATE NULL,
    CellPhone VARCHAR(20) NULL,
    Email NVARCHAR(254) NULL,
    HasValidMembership BIT NOT NULL,
    MedicalCheckValidUntil DATE NULL,
    CertificationLevel NVARCHAR(30) NULL
);
GO

GO

GO

GO

GO

GO

GO

GO

GO

GO

GO

GO

SELECT
    f.NationalId,
    f.FirstName,
    f.LastName,
    f.Gender,
    f.DateOfBirth,
    f.CellPhone,
    f.Email
FROM #FilteredFederationMembers f;
GO

SELECT
    p.PersonId,
    f.HasValidMembership,
    f.MedicalCheckValidUntil,
    f.CertificationLevel
FROM #FilteredFederationMembers f
JOIN Person p
    ON p.NationalId = f.NationalId;
GO

DROP TABLE #FilteredFederationMembers;
GO


GO


USE RideOn;
GO

/* =========================================================
   SEED DATA - SYSTEM USERS
   Username = Email
   PasswordHash = NULL
   ========================================================= */

IF OBJECT_ID('tempdb..#SystemUserSeed') IS NOT NULL
    DROP TABLE #SystemUserSeed;
GO

CREATE TABLE #SystemUserSeed
(
    NationalId CHAR(9) NULL,
    FirstName NVARCHAR(50) NOT NULL,
    LastName NVARCHAR(50) NOT NULL,
    Username NVARCHAR(100) NOT NULL
);
GO

GO


SELECT
    p.PersonId,
    s.Username,
    NULL
FROM #SystemUserSeed s
JOIN Person p
    ON (
        s.NationalId IS NOT NULL
        AND p.NationalId = s.NationalId
    )
    OR (
        s.NationalId IS NULL
        AND p.FirstName = s.FirstName
        AND p.LastName = s.LastName
        AND ISNULL(p.Email, '') = ISNULL(s.Username, '')
    )
WHERE NOT EXISTS (
    SELECT 1
    FROM SystemUser su
    WHERE su.SystemUserId = p.PersonId
);
GO

